mapper.select:
select reportid, phase, aprvlineid, approvalid, report_type, date_from, date_to, val1, val2, val3, DATE_FORMAT(apply_date,'%Y/%m/%d') as apply_date, apply_userid, DATE_FORMAT(approve_date,'%Y/%m/%d') as approve_date, approve_userid
  from cotdl.tbl_piireport 
 where reportid= #{reportid, jdbcType=VARCHAR}

mapper.update:
update cotdl.tbl_piireport
set phase= 'REJECTED'
where reportid= #{reportid}
